// Package firmware was generated by IDLC from Firmware.idl.
// It is part of module firmware.
// The remaining comment is for module firmware.
//
// Firmware Management
package firmware

import (
	"context"
	"time"

	"github.com/arminguenther/xeruspower-go/v40020/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40020/idl"
	"github.com/arminguenther/xeruspower-go/v40020/idl/event"
)

// Firmware update history status
type UpdateHistoryStatus int

const (
	SUCCESSFUL UpdateHistoryStatus = iota // The update was successfully completed
	FAILED                                // The update failed
	INCOMPLETE                            // The update was not completed
)

// Firmware update history entry
// TODO: implement CR# 45668 on next interface change
//
//	add comment field based on firmware tag "char tag[64];"
//	to improve firmware update history entries without rootfs images
type UpdateHistoryEntry struct {
	Timestamp    time.Time           // UNIX timestamp (UTC) when the update was started
	OldVersion   string              // Previous firmware version
	ImageVersion string              // Firmware version of update image
	ImageMD5     string              // MD5 hash of update image
	Status       UpdateHistoryStatus // Update status
}

// Image upload/download state
type ImageState int

const (
	NONE            ImageState = iota // No firmware image has been uploaded/downloaded
	UPLOADING                         // A firmware image is currently being uploaded
	UPLOAD_FAILED                     // There was a problem uploading an image to the device
	DOWNLOADING                       // The device is downloading a firmware image from a URL
	DOWNLOAD_FAILED                   // There was a problem downloading the image from a URL
	COMPLETE                          // A complete image has been successfully uploaded/downloaded
)

// Image upload/download status
type ImageStatus struct {
	State         ImageState // Image upload/download state
	Error_message string     // Error message; empty if there was no error
	Time_started  time.Time  // UNIX timestamp (UTC) of the last state change (if available)
	Size_total    int32      // Total size of the image (if available)
	Size_done     int32      // Progress of the running upload or download (if available)
}

// Firmware image information
type ImageInfo struct {
	Valid                 bool   // The file is a valid firmware image
	Version               string // Firmware image version
	Min_required_version  string // Minimum running firmware version for image
	Min_downgrade_version string // Minimum image version for running firmware
	Product               string // Product name
	Platform              string // Platform name
	Oem                   string // OEM name
	Hwid_whitelist        string // Hardware ID whitelist
	Hwid_blacklist        string // Hardware ID blacklist
	Compatible            bool   // true if the image is compatible with this device
	Signature_present     bool   // true if the image is signed
	Signed_by             string // Signature issuer
	Signature_good        bool   // true if the signature is valid
	Certified_by          string // Key certificate issuer
	Certificate_good      bool   // true if the key certificate is valid
	Model_list_present    bool   // true if the image includes a supported models list
	Model_supported       bool   // true if the model is found on the support list
}

// Flags for startUpdate() method
type UpdateFlags int

const (
	CROSS_OEM       UpdateFlags = iota // Ignore version, product and OEM constraints
	CROSS_HW                           // Ignore hardware constraints
	ALLOW_UNTRUSTED                    // Allow untrusted firmwares (ignored when secure boot is active)
)

// Event: System startup finished
type SystemStartupEvent interface {
	event.Event
	isSystemStartupEvent()
}

// Event: System shutdown started
type SystemShutdownEvent interface {
	userevent.UserEvent
	isSystemShutdownEvent()
}

// Event: Firmware validation failed
type ValidationFailedEvent interface {
	userevent.UserEvent
	isValidationFailedEvent()
}

// Event: Firmware update base event
type UpdateEvent interface {
	userevent.UserEvent
	OldVersion() string // Firmware version the device is being upgraded from
	NewVersion() string // Firmware version the device is being upgraded to
	isUpdateEvent()
}

// Event: Firmware update started
type UpdateStartedEvent interface {
	UpdateEvent
	isUpdateStartedEvent()
}

// Event: Firmware updated successfully
type UpdateCompletedEvent interface {
	UpdateEvent
	isUpdateCompletedEvent()
}

// Event: Firmware update failed
type UpdateFailedEvent interface {
	UpdateEvent
	isUpdateFailedEvent()
}

// Firmware management methods
type Firmware interface {
	idl.Object

	// Reboot the device.
	//
	// This function will fail if a firmware update is in progress.
	Reboot(ctx context.Context) error

	// Reset the device configuration to factory defaults.
	FactoryReset(ctx context.Context) error

	// Reset all device data to factory defaults. This includes energy
	// counters, firmware update history and reliability data.
	//
	//	@note This command is only available during manufacturing!
	//
	//	@return 0 if OK
	//	@return 1 if not in production mode
	HardFactoryReset(ctx context.Context) (int32, error)

	// Semi-hard factory reset for manufacturing.
	//
	// This command clears both the user and system configuration layer,
	// but keeps the ETO cache and subcontroller security association.
	//
	//	@note This command is only available during manufacturing!
	//
	//	@return 0 if OK
	//	@return 1 if not in production mode
	ManufacturingReset(ctx context.Context) (int32, error)

	// Returns the currently installed firmware version.
	//
	//	@return Firmware version
	GetVersion(ctx context.Context) (string, error)

	// Fetch the firmware update history.
	//
	//	@return Vector of firmware update history entries
	GetUpdateHistory(ctx context.Context) ([]UpdateHistoryEntry, error)

	// Get the current firmware image upload/download status.
	//
	//	@return Image status structure.
	GetImageStatus(ctx context.Context) (ImageStatus, error)

	// Discard the currently uploaded firmware image, cancel the update.
	DiscardImage(ctx context.Context) error

	// Return information about a currently uploaded firmware image.
	//
	//	@param info  Firmware image information
	//
	//	@return true if a firmware image is uploaded, false otherwise.
	GetImageInfo(ctx context.Context) (ret bool, info ImageInfo, err error)

	// Launch the firmware update process. The device will stop handling
	// RPC requests shortly after this method has been successfully called.
	// The client should poll the fwupdate_progress.cgi page to monitor the
	// update progress.
	//
	//	@param flags  List of firmware update flags; may be empty
	StartUpdate(ctx context.Context, flags []UpdateFlags) error
}
